import { useState, useCallback, useRef, useEffect } from 'react';

const NOTIFICATION_SOUND = 'data:audio/mpeg;base64,';

function playNotificationSound() {
    try {
        const audio = new Audio(NOTIFICATION_SOUND);
        audio.volume = 0.3;
        audio.play().catch(() => {});
    } catch (e) {}
}

function fileToBase64(file) {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => {
            const dataUrl = reader.result;
            const base64 = dataUrl.split(',')[1];
            resolve({ data: base64, mimeType: file.type, dataUrl });
        };
        reader.onerror = reject;
        reader.readAsDataURL(file);
    });
}

export default function useChat(config) {
    const storageKey = `aiwidget_${config.clientId}_messages`;
    const sessionKey = `aiwidget_${config.clientId}_session`;

    const [messages, setMessages] = useState(() => {
        try {
            const saved = localStorage.getItem(storageKey);
            return saved ? JSON.parse(saved) : [];
        } catch {
            return [];
        }
    });
    const [isLoading, setIsLoading] = useState(false);
    const [isTyping, setIsTyping] = useState(false);
    const [isOffline, setIsOffline] = useState(typeof navigator !== 'undefined' ? !navigator.onLine : false);

    // Persist session ID across page loads for conversation memory
    const sessionIdRef = useRef(() => {
        try {
            const saved = localStorage.getItem(sessionKey);
            if (saved) return saved;
        } catch {}
        const newId = `session_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
        try { localStorage.setItem(sessionKey, newId); } catch {}
        return newId;
    });
    // Initialize sessionId (useRef with function needs manual init)
    if (typeof sessionIdRef.current === 'function') {
        sessionIdRef.current = sessionIdRef.current();
    }

    const messagesRef = useRef(messages);
    const isReturningUser = useRef(messages.length > 0).current;

    useEffect(() => {
        messagesRef.current = messages;
    }, [messages]);

    // Persist messages (strip imageUrl to save space)
    useEffect(() => {
        try {
            const messagesToSave = messages.slice(-50).map((m) => {
                const { imageUrl, ...rest } = m;
                return rest;
            });
            localStorage.setItem(storageKey, JSON.stringify(messagesToSave));
        } catch {}
    }, [messages, storageKey]);

    useEffect(() => {
        const goOnline = () => setIsOffline(false);
        const goOffline = () => setIsOffline(true);
        window.addEventListener('online', goOnline);
        window.addEventListener('offline', goOffline);
        return () => {
            window.removeEventListener('online', goOnline);
            window.removeEventListener('offline', goOffline);
        };
    }, []);

    const sendMessage = useCallback(
        async (content, historyOverride, imageFile) => {
            if (isOffline) {
                setMessages((prev) => [
                    ...prev,
                    { role: 'user', content, timestamp: Date.now() },
                    {
                        role: 'assistant',
                        content: 'You are offline. Please check your connection and try again.',
                        timestamp: Date.now(),
                        isError: true,
                    },
                ]);
                return;
            }

            // Process image if provided
            let imageData = null;
            let imageUrl = null;

            if (imageFile) {
                try {
                    const result = await fileToBase64(imageFile);
                    imageData = { data: result.data, mimeType: result.mimeType };
                    imageUrl = result.dataUrl;
                } catch (e) {
                    console.error('Failed to process image:', e);
                }
            }

            const userMsg = {
                role: 'user',
                content,
                timestamp: Date.now(),
                ...(imageUrl && { imageUrl }),
            };
            setMessages((prev) => [...prev, userMsg]);
            setIsLoading(true);
            setIsTyping(true);

            try {
                const history = historyOverride !== undefined ? historyOverride : messagesRef.current;

                // Collect page context for AI awareness
                let pageContext = {};
                try {
                    pageContext.title = document.title || '';
                    pageContext.url = window.location.href || '';
                    pageContext.path = window.location.pathname || '';
                    const metaDesc = document.querySelector('meta[name="description"]');
                    if (metaDesc) pageContext.description = metaDesc.getAttribute('content') || '';
                    const h1s = Array.from(document.querySelectorAll('h1')).map(h => h.textContent?.trim()).filter(Boolean);
                    if (h1s.length) pageContext.headings = h1s.slice(0, 3);
                } catch (e) {}

                const body = {
                    clientId: config.clientId,
                    message: content,
                    conversationHistory: history
                        .filter((m) => !m.isError)
                        .map((m) => ({ role: m.role, content: m.content })),
                    sessionId: sessionIdRef.current,
                    metadata: { pageContext },
                };

                // Add image data if present
                if (imageData) {
                    body.image = imageData;
                }

                const response = await fetch((window.__WIDGET_API_BASE__ || '') + '/api/chat/stream', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(body),
                });

                if (!response.ok) {
                    const errorData = await response.json().catch(() => ({}));
                    throw new Error(errorData.error || 'Stream failed');
                }

                const reader = response.body.getReader();
                const decoder = new TextDecoder();
                let botContent = '';

                // Add bot message placeholder
                setMessages((prev) => [...prev, { role: 'assistant', content: '', timestamp: Date.now() }]);
                setIsTyping(false);

                while (true) {
                    const { done, value } = await reader.read();
                    if (done) break;

                    const chunk = decoder.decode(value, { stream: true });
                    const lines = chunk.split('\n\n');

                    for (const line of lines) {
                        if (line.startsWith('data: ')) {
                            const payload = line.slice(6);
                            if (payload === '[DONE]') break;
                            try {
                                const data = JSON.parse(payload);
                                if (data.token) {
                                    botContent += data.token;
                                    // Strip :::block syntax during streaming (complete + incomplete blocks)
                                    const displayContent = botContent.replace(/:::(card|buttons|carousel|form)\n[\s\S]*?:::/g, '').replace(/:::(card|buttons|carousel|form)[\s\S]*$/g, '').trim();
                                    setMessages((prev) => {
                                        const newMsgs = [...prev];
                                        newMsgs[newMsgs.length - 1] = {
                                            ...newMsgs[newMsgs.length - 1],
                                            content: displayContent,
                                        };
                                        return newMsgs;
                                    });
                                }
                                if (data.rich) {
                                    setMessages((prev) => {
                                        const newMsgs = [...prev];
                                        newMsgs[newMsgs.length - 1] = {
                                            ...newMsgs[newMsgs.length - 1],
                                            richBlocks: data.rich,
                                        };
                                        return newMsgs;
                                    });
                                }
                            } catch (e) {}
                        }
                    }
                }

                // Clean :::block syntax from final content (complete + incomplete/malformed blocks)
                botContent = botContent.replace(/:::(card|buttons|carousel|form)\n[\s\S]*?:::/g, '').replace(/:::(card|buttons|carousel|form)[\s\S]*$/g, '').trim();

                // Parse follow-up suggestions from response
                const sugMatch = botContent.match(/\[SUGGESTIONS\](.*?)\[\/SUGGESTIONS\]/s);
                if (sugMatch) {
                    const suggestions = sugMatch[1].split('|').map(s => s.trim()).filter(Boolean).slice(0, 3);
                    botContent = botContent.replace(/\[SUGGESTIONS\].*?\[\/SUGGESTIONS\]/s, '').trim();
                    setMessages((prev) => {
                        const newMsgs = [...prev];
                        newMsgs[newMsgs.length - 1] = {
                            ...newMsgs[newMsgs.length - 1],
                            content: botContent,
                            suggestions,
                        };
                        return newMsgs;
                    });
                }

                if (config.features?.sound !== false && !window.__WIDGET_MUTED__) {
                    playNotificationSound();
                }
            } catch (error) {
                console.error('Chat Error:', error);
                setMessages((prev) => {
                    const cleaned = prev.filter((m) => !(m.role === 'assistant' && m.content === ''));
                    return [
                        ...cleaned,
                        {
                            role: 'assistant',
                            content: 'Connection error. Please try again.',
                            timestamp: Date.now(),
                            isError: true,
                        },
                    ];
                });
            } finally {
                setIsLoading(false);
                setIsTyping(false);
            }
        },
        [config.clientId, config.features?.sound, isOffline]
    );

    const retryLastMessage = useCallback(() => {
        const msgs = messagesRef.current;
        for (let i = msgs.length - 1; i >= 0; i--) {
            if (msgs[i].role === 'user') {
                const content = msgs[i].content;
                const history = msgs.slice(0, i);
                setMessages(history);
                sendMessage(content, history);
                return;
            }
        }
    }, [sendMessage]);

    const clearMessages = useCallback(() => {
        setMessages([]);
        try {
            localStorage.removeItem(storageKey);
            localStorage.removeItem(sessionKey);
        } catch {}
        const newId = `session_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
        sessionIdRef.current = newId;
        try { localStorage.setItem(sessionKey, newId); } catch {}
    }, [storageKey, sessionKey]);

    return {
        messages,
        sendMessage,
        isLoading,
        isTyping,
        isOffline,
        retryLastMessage,
        clearMessages,
        sessionId: sessionIdRef.current,
        isReturningUser,
    };
}
